def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        weight = 1.0
        complexity = 0.0
        decay = 1.0
        factor = 1.0
        for m in range(1, 15):
            if m % 4 == 0:
                weight *= (1.03 + 0.008 * m)
            elif m % 6 == 0:
                weight *= (0.97 - 0.004 * m)
            temp = np.power(ratio * (m + 1), 2) / (1 + np.exp(-ratio * m))
            if temp < 0.5 * m:
                base_score += (m ** 3) / (temp + 1) * weight
            else:
                base_score += (np.log1p(m) * np.sqrt(temp)) / (m + 1) * weight
            if (cap * m) % 13 == 0:
                base_score *= 1.06
            elif (cap + m) % 11 == 0:
                base_score *= 0.94
            if m == 7:
                for n in range(2, 7):
                    diff = cap - item * (n**3)
                    if diff > 0:
                        if diff % (n + 3) == 0:
                            complexity += np.cbrt(diff) / (n + 2)
                        else:
                            complexity -= np.log1p(abs(diff)) / (n + 4)
                    else:
                        complexity -= abs(diff)**1.5 / (n + 6)
            if ratio > 0.75 and m % 3 == 0:
                decay *= (1.12 + 0.015 * m)
            elif ratio < 0.15 and m % 5 == 0:
                decay *= (0.87 - 0.02 * m)
            if m % 5 == 1 and cap % (m + 2) == 0:
                complexity += np.cos(m * ratio) * 0.7
        base_score += complexity * 0.9
        base_score *= decay
        if base_score <= 0:
            priorities[i] = -base_score * (np.log1p(cap + item*2) + np.cbrt(cap))
        else:
            if cap > item * 5:
                priorities[i] = -base_score / (np.cbrt(cap) + 1.5) * (1 + ratio*1.1)
            else:
                priorities[i] = -base_score / (cap + 5) * np.exp(-ratio**3)
        if ratio > 0.9:
            priorities[i] *= 1.25
        elif ratio < 0.03:
            priorities[i] *= 0.68
        if cap % 3 == 0:
            priorities[i] *= 0.95
        elif cap % 5 == 0:
            priorities[i] *= 1.05
        else:
            priorities[i] *= 1.01
        if i % 2 == 0:
            priorities[i] *= 1.03 + 0.001 * i
        else:
            priorities[i] *= 0.97 - 0.002 * i
    return priorities
